			System.out.println("evalFactory=" + storeState.evaluationFactoryClass());
			System.out.println("optimizerPipeline=" + storeState.optimizerPipelineClass());
			System.out.println("supportsJoinEstimation=" + storeState.supportsJoinEstimation());
			System.out.println("sketchState=" + storeState.sketchState());
			System.out.println("resultRows=" + resultRows());
			System.out.println("elapsedMicros=" + (elapsedNanos() / 1_000.0));
